"use client";

import * as React from "react";

import { cn } from "@/lib/utils";

import { NavbarLogo } from "./navbar-logo";
import { NavbarNavItems } from "./navbar-nav-items";
import { NavbarProfileMenu } from "./navbar-profile-menu";
import { NavbarTrailingActions } from "./navbar-trailing-actions";
import type { NavbarProps } from "./types";

export function Navbar({
  logo,
  navItems,
  profile,
  trailingActions,
  className,
}: NavbarProps) {
  return (
    <header
      className={cn(
        "flex w-full items-center gap-3 bg-[#fff] py-[12px] rounded-b-[32px] px-[80px] ",
        className,
      )}
    >
      <div className="flex min-w-0 flex-1 items-center gap-[48px] sm:gap-6">
        <NavbarLogo logo={logo} />
        <NavbarNavItems items={navItems} />
      </div>

      <div className="flex shrink-0 items-center gap-[24px]">
        <NavbarTrailingActions items={trailingActions ?? []} />
        <NavbarProfileMenu profile={profile} />
      </div>
    </header>
  );
}

import type { MouseEventHandler, ReactNode } from "react"

/** Hover + active text/icon color for primary nav and profile menu (keep Tailwind `text-[#6962AC]` in sync). */
export const NAVBAR_ACCENT_HEX = "#6962AC" as const

export type NavbarHref = string

export type NavbarLinkItem = {
  id?: string
  label: string
  href: NavbarHref
  /** When omitted, `http(s)://` URLs open in a new tab; app paths stay in the same tab. */
  openInNewTab?: boolean
  /**
   * Fires on the anchor click before navigation. Call `event.preventDefault()` to handle
   * routing or actions yourself (e.g. Next.js `router.push`).
   */
  onClick?: MouseEventHandler<HTMLAnchorElement>
  /**
   * Mark the current route (or logical section). Renders accent color and an underline;
   * set from the consuming app (e.g. compare `pathname` to `href`).
   */
  isActive?: boolean
}

export type NavbarLogo = {
  src: string
  alt: string
  href: NavbarHref
  openInNewTab?: boolean
  /** Same as link items: optional handler on the logo anchor (e.g. `preventDefault` + client routing). */
  onClick?: MouseEventHandler<HTMLAnchorElement>
}

export type NavbarProfileMenuItem = NavbarLinkItem & {
  /** Leading icon next to the label (treat as decorative when `label` is set). */
  icon?: ReactNode
}

export type NavbarProfile = {
  avatarSrc?: string
  avatarAlt?: string
  /** Shown when there is no `avatarSrc` (typically initials). */
  fallbackText?: string
  menuItems: NavbarProfileMenuItem[]
  /** Accessible name for the profile menu trigger. */
  menuTriggerLabel?: string
}

export type NavbarTextAction = {
  id?: string
  type: "text"
  label: string
  href: NavbarHref
  openInNewTab?: boolean
  onClick?: MouseEventHandler<HTMLAnchorElement>
}

export type NavbarIconAction = {
  id?: string
  type: "icon"
  icon: ReactNode
  ariaLabel: string
  href: NavbarHref
  openInNewTab?: boolean
  onClick?: MouseEventHandler<HTMLAnchorElement>
  /** Shown as the native browser tooltip on hover (e.g. "Calendar"). */
  tooltip?: string
}

export type NavbarImageAction = {
  id?: string
  type: "image"
  src: string
  alt: string
  href: NavbarHref
  openInNewTab?: boolean
  /** Optional classes for the `<img>` (size, object-fit, etc.). */
  imageClassName?: string
  onClick?: MouseEventHandler<HTMLAnchorElement>
  /** Native tooltip on hover (e.g. "Download app"). */
  tooltip?: string
}

export type NavbarActionItem = NavbarTextAction | NavbarIconAction | NavbarImageAction

export type NavbarProps = {
  logo: NavbarLogo
  navItems: NavbarLinkItem[]
  profile: NavbarProfile
  /** Shown to the left of the profile control (text links and/or icon buttons). */
  trailingActions?: NavbarActionItem[]
  className?: string
}

"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

export type NavbarAnchorProps = Omit<
  React.AnchorHTMLAttributes<HTMLAnchorElement>,
  "href"
> & {
  href: string
  openInNewTab?: boolean
}

function resolveOpenInNewTab(href: string, openInNewTab?: boolean) {
  if (typeof openInNewTab === "boolean") {
    return openInNewTab
  }

  return /^https?:\/\//i.test(href)
}

export const NavbarAnchor = React.forwardRef<HTMLAnchorElement, NavbarAnchorProps>(
  function NavbarAnchor(
    { href, openInNewTab, className, children, ...rest },
    ref,
  ) {
    const external = resolveOpenInNewTab(href, openInNewTab)

    return (
      <a
        ref={ref}
        href={href}
        className={cn(className)}
        {...(external ? { target: "_blank", rel: "noreferrer noopener" } : {})}
        {...rest}
        suppressHydrationWarning
      >
        {children}
      </a>
    )
  },
)

NavbarAnchor.displayName = "NavbarAnchor"

"use client"

import * as React from "react"

import { NavbarAnchor } from "./navbar-anchor"
import type { NavbarLogo as NavbarLogoConfig } from "./types"

type NavbarLogoProps = {
  logo: NavbarLogoConfig
  className?: string
}

export function NavbarLogo({ logo, className }: NavbarLogoProps) {
  return (
    <NavbarAnchor
      href={logo.href}
      openInNewTab={logo.openInNewTab}
      onClick={logo.onClick}
      className={`inline-flex shrink-0 cursor-pointer items-center rounded-md shadow-none outline-none ring-offset-background transition-opacity hover:opacity-90 hover:shadow-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-0 ${className ?? ""}`.trim()}
    >
      <img
        src={logo.src}
        alt={logo.alt}
        className="h-8 w-auto max-w-[160px] object-contain"
        loading="eager"
        decoding="async"
        suppressHydrationWarning
      />
    </NavbarAnchor>
  )
}

"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

import { NavbarAnchor } from "./navbar-anchor"
import type { NavbarLinkItem } from "./types"

type NavbarNavItemsProps = {
  items: NavbarLinkItem[]
  className?: string
}

export function NavbarNavItems({ items, className }: NavbarNavItemsProps) {
  if (!items.length) {
    return null
  }

  return (
    <nav
      aria-label="Primary"
      className={`flex min-w-0 flex-1 flex-wrap items-center gap-1 sm:gap-2 ${className ?? ""}`.trim()}
    >
      <ul className="flex flex-wrap items-center gap-[16px] sm:gap-3">
        {items.map((item, index) => (
          <li key={item.id ?? `${item.href}-${item.label}-${index}`}>
            <NavbarAnchor
              href={item.href}
              openInNewTab={item.openInNewTab}
              onClick={item.onClick}
              aria-current={item.isActive ? "page" : undefined}
              className={cn(
                "cursor-pointer rounded-md px-2 py-1.5 font-poppins text-[16px] font-[500] leading-[24px] shadow-none transition-colors hover:shadow-none focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-0",
                "text-muted-foreground hover:text-[#6962AC]",
                item.isActive &&
                  "font-medium text-[#6962AC] underline decoration-2 underline-offset-[6px]",
              )}
            >
              {item.label}
            </NavbarAnchor>
          </li>
        ))}
      </ul>
    </nav>
  )
}

"use client";

import * as DropdownMenu from "@radix-ui/react-dropdown-menu";
import * as React from "react";

import { cn } from "@/lib/utils";

import { NavbarAnchor } from "./navbar-anchor";
import type { NavbarProfile } from "./types";

type NavbarProfileMenuProps = {
  profile: NavbarProfile;
  className?: string;
};

function initials(value: string) {
  const parts = value.trim().split(/\s+/).filter(Boolean);
  if (!parts.length) {
    return "?";
  }

  if (parts.length === 1) {
    return parts[0].slice(0, 2).toUpperCase();
  }

  return `${parts[0][0] ?? ""}${parts[parts.length - 1][0] ?? ""}`.toUpperCase();
}

const menuItemClassName =
  "flex cursor-pointer select-none items-center gap-2 rounded-sm px-3 py-2 text-sm shadow-none outline-none transition-colors text-[#6B7280] hover:text-[#6962AC] data-[highlighted]:text-[#6962AC] data-[highlighted]:shadow-none data-[disabled]:pointer-events-none data-[disabled]:opacity-50"

const menuContentClassName =
  "z-50 min-w-[200px] overflow-hidden rounded-md border border-border bg-popover p-1 text-popover-foreground shadow-md";

export function NavbarProfileMenu({
  profile,
  className,
}: NavbarProfileMenuProps) {
  const label =
    profile.menuTriggerLabel ??
    profile.avatarAlt ??
    profile.fallbackText ??
    "Account menu";

  return (
    <div className={cn("shrink-0", className)}>
      <DropdownMenu.Root>
        <DropdownMenu.Trigger asChild>
          <button
            type="button"
            className="inline-flex size-10 cursor-pointer items-center justify-center rounded-full border border-border bg-background text-sm font-semibold text-foreground shadow-none outline-none ring-offset-background transition-colors hover:bg-accent hover:shadow-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-0 data-[state=open]:ring-2 data-[state=open]:ring-ring data-[state=open]:ring-offset-0"
            aria-label={label}
            suppressHydrationWarning
          >
            {profile.avatarSrc ? (
              <img
                src={profile.avatarSrc}
                alt={profile.avatarAlt ?? "Profile photo"}
                className="size-full rounded-full object-cover"
                loading="lazy"
                decoding="async"
                suppressHydrationWarning
              />
            ) : (
              <span aria-hidden="true">
                {initials(profile.fallbackText ?? profile.avatarAlt ?? "User")}
              </span>
            )}
          </button>
        </DropdownMenu.Trigger>

        <DropdownMenu.Portal>
          <DropdownMenu.Content
            className={menuContentClassName}
            sideOffset={8}
            align="end"
            collisionPadding={12}
          >
            {profile.menuItems.length === 0 ? (
              <div className="px-3 py-2 text-xs text-muted-foreground">
                No menu items.
              </div>
            ) : (
              profile.menuItems.map((item, index) => (
                <DropdownMenu.Item
                  key={item.id ?? `${item.href}-${item.label}-${index}`}
                  asChild
                >
                  <NavbarAnchor
                    href={item.href}
                    openInNewTab={item.openInNewTab}
                    onClick={item.onClick}
                    aria-current={item.isActive ? "page" : undefined}
                    className={cn(
                      menuItemClassName,
                      item.isActive &&
                        "font-medium text-[#6962AC] data-[highlighted]:text-[#6962AC]",
                    )}
                  >
                    {item.icon ? (
                      <span
                        className="flex size-4 shrink-0 items-center justify-center text-inherit [&_svg]:size-4"
                        aria-hidden
                      >
                        {item.icon}
                      </span>
                    ) : null}
                    <span
                      className={cn(
                        "min-w-0 flex-1 text-[16px] font-[500] leading-[24px]",
                        item.isActive &&
                          "underline decoration-2 underline-offset-4 text-[#6962AC]",
                        !item.isActive && "text-inherit",
                      )}
                    >
                      {item.label}
                    </span>
                  </NavbarAnchor>
                </DropdownMenu.Item>
              ))
            )}
          </DropdownMenu.Content>
        </DropdownMenu.Portal>
      </DropdownMenu.Root>
    </div>
  );
}

"use client";

import * as React from "react";

import { NavbarAnchor } from "./navbar-anchor";
import type { NavbarActionItem } from "./types";

type NavbarTrailingActionsProps = {
  items: NavbarActionItem[];
  className?: string;
};

export function NavbarTrailingActions({
  items,
  className,
}: NavbarTrailingActionsProps) {
  if (!items.length) {
    return null;
  }

  return (
    <div
      className={`flex shrink-0 items-center gap-[16px] ${className ?? ""}`.trim()}
    >
      {items.map((item, index) => {
        const key = item.id ?? `${item.type}-${item.href}-${index}`;

        if (item.type === "text") {
          return (
            <NavbarAnchor
              key={key}
              href={item.href}
              openInNewTab={item.openInNewTab}
              onClick={item.onClick}
              className="cursor-pointer rounded-md px-2 py-1.5 text-sm font-medium text-muted-foreground shadow-none transition-colors hover:text-[#6962AC] hover:shadow-none focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-0"
            >
              {item.label}
            </NavbarAnchor>
          );
        }

        if (item.type === "image") {
          const imageClassName = item.imageClassName?.trim().length
            ? item.imageClassName
            : "size-8 max-h-9 object-contain";

          return (
            <NavbarAnchor
              key={key}
              href={item.href}
              openInNewTab={item.openInNewTab}
              onClick={item.onClick}
              title={item.tooltip}
              className="inline-flex cursor-pointer items-center justify-center rounded-md p-1 text-muted-foreground shadow-none transition-opacity hover:opacity-90 hover:shadow-none focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-0"
            >
              <img
                src={item.src}
                alt={item.alt}
                className={imageClassName}
                loading="lazy"
                decoding="async"
                suppressHydrationWarning
              />
            </NavbarAnchor>
          );
        }

        return (
          <NavbarAnchor
            key={key}
            href={item.href}
            openInNewTab={item.openInNewTab}
            onClick={item.onClick}
            aria-label={item.ariaLabel}
            title={item.tooltip}
            className="inline-flex size-9 cursor-pointer items-center justify-center rounded-full text-muted-foreground shadow-none transition-colors hover:text-[#6962AC] hover:shadow-none focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-0"
          >
            {item.icon}
          </NavbarAnchor>
        );
      })}
    </div>
  );
}
